# ❌ ANTI-PATTERN: Loading full model for every request
from transformers import AutoModelForSequenceClassification, AutoTokenizer
import torch

def classify_delivery_type_bad(text):
    # PROBLEM: Loads 400MB model every single inference!
    model = AutoModelForSequenceClassification.from_pretrained(
        "bert-base-uncased"
    )
    tokenizer = AutoTokenizer.from_pretrained("bert-base-uncased")

    inputs = tokenizer(text, return_tensors="pt")
    with torch.no_grad():
        outputs = model(**inputs)
    return outputs.logits.argmax(-1).item()

# ✅ BEST PRACTICE: Singleton pattern with lazy initialization
class CricketDeliveryClassifier:
    _instance = None
    _base_model = None
    _fast_model = None  # Distilled version

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self.tokenizer = AutoTokenizer.from_pretrained("bert-base-uncased")
        # Load only on first use
        self._base_model = None
        self._fast_model = None
        self._initialized = True

    def _load_base_model(self):
        if self._base_model is None:
            self._base_model = AutoModelForSequenceClassification.from_pretrained(
                "bert-base-uncased"
            ).eval()
        return self._base_model

    def _load_fast_model(self):
        if self._fast_model is None:
            self._fast_model = AutoModelForSequenceClassification.from_pretrained(
                "distilbert-base-uncased"
            ).eval()
        return self._fast_model

    def classify(self, text, use_fast=True):
        """Adaptive pattern: use fast model for routine cases"""
        inputs = self.tokenizer(text, return_tensors="pt")

        if use_fast:
            model = self._load_fast_model()
            confidence_threshold = 0.85
        else:
            model = self._load_base_model()
            confidence_threshold = 0.0

        with torch.no_grad():
            outputs = model(**inputs)
            logits = outputs.logits
            probs = torch.softmax(logits, dim=-1)
            confidence = probs.max().item()
            prediction = logits.argmax(-1).item()

        # Cascade: if uncertain with fast model, rerun with base
        if use_fast and confidence < confidence_threshold:
            return self.classify(text, use_fast=False)

        return {
            "delivery_type": prediction,
            "confidence": confidence,
            "model_used": "distilbert" if use_fast else "bert"
        }

# Usage
classifier = CricketDeliveryClassifier()
result = classifier.classify("Fast yorker at stumps")
print(result)  # Single model instance, 60% faster than anti-pattern
